            int b1 = int.Parse(tokens[idx++]), c1 = int.Parse(tokens[idx++]);
            if (t == 1) roots.Add(Update(roots[a1], 0, n - 1, b1, c1));
            else results.Add(Query(roots[a1], 0, n - 1, b1, c1).ToString());
        }
        Console.WriteLine(string.Join(" ", results));
    }
}

